<script setup>
import { computed, onMounted, reactive, ref } from 'vue';
import Layout from '../Layout.vue';
import FixedAssetApi from './FixedAssetApi';

defineProps({ page: { type: String, default: 'fixed-assets' }, title: { type: String, default: 'Fixed Assets' } });

const today = new Date().toISOString().slice(0, 10);
const tab = ref('dashboard');
const loading = ref(false);
const saving = ref(false);
const errors = ref({});
const refs = ref({ accounts: [], branches: [], warehouses: [], suppliers: [], categories: [], locations: [], assets: [], settings: {} });
const dashboard = ref({});
const categories = ref([]);
const locations = ref([]);
const assets = ref([]);
const acquisitions = ref([]);
const runs = ref([]);
const reports = ref({});
const filters = reactive({ search: '', branch_id: '', asset_category_id: '', asset_status: '' });

const category = reactive({ category_code: '', category_name: '', parent_id: '', asset_account_id: '', accumulated_depreciation_account_id: '', depreciation_expense_account_id: '', default_depreciation_method: 'straight_line', default_useful_life_months: 60, default_depreciation_rate: '', default_residual_value_percent: 0, capitalisation_threshold: '', status: 'active' });
const location = reactive({ branch_id: '', warehouse_id: '', parent_id: '', location_code: '', location_name: '', location_type: 'office', floor: '', room: '', rack: '', description: '', status: 'active' });
const asset = reactive({ branch_id: '', asset_category_id: '', asset_tag: '', asset_name: '', description: '', manufacturer: '', model_number: '', serial_number: '', barcode: '', supplier_id: '', acquisition_date: today, capitalization_date: '', put_to_use_date: '', purchase_cost: 0, additional_cost: 0, residual_value: 0, depreciation_method: 'straight_line', useful_life_months: 60, depreciation_rate: '', current_location_id: '', assigned_employee_id: '', ownership_type: 'owned', condition_status: 'new', asset_status: 'draft', warranty_start_date: '', warranty_end_date: '', remarks: '' });
const acquisition = reactive({ branch_id: '', acquisition_date: today, source_type: 'manual', supplier_id: '', invoice_number: '', invoice_date: '', asset_category_id: '', quantity: 1, base_cost: 0, additional_cost: 0, tax_amount: 0, input_tax_credit_eligible: true, non_creditable_tax_amount: 0, payment_status: 'unpaid', status: 'draft', narration: '' });
const cap = reactive({ branch_id: '', capitalization_date: today, source_type: 'manual', source_id: 1, fixed_asset_id: '', asset_category_id: '', capitalized_amount: 0, put_to_use_date: today, asset_location_id: '', assigned_employee_id: '', asset_name: '', asset_tag: '', status: 'posted', narration: '' });
const dep = reactive({ branch_id: '', financial_year: '2026-27', period_start: today.slice(0, 8) + '01', period_end: today, posting_date: today, status: 'calculated' });
const assign = reactive({ fixed_asset_id: '', assigned_to_employee_id: '', assigned_to_department_id: '', assigned_location_id: '', assignment_date: today, expected_return_date: '', condition_at_issue: 'good', issue_notes: '' });
const transfer = reactive({ transfer_date: today, source_branch_id: '', destination_branch_id: '', source_location_id: '', destination_location_id: '', transfer_type: 'location_transfer', status: 'draft', remarks: '', items: [{ fixed_asset_id: '', source_employee_id: '', destination_employee_id: '', condition_before: 'good', condition_after: '' }] });
const maintenance = reactive({ fixed_asset_id: '', request_date: today, maintenance_type: 'preventive', issue_description: '', priority: 'medium', assigned_vendor_id: '', assigned_employee_id: '', expected_start_date: '', expected_completion_date: '', estimated_cost: 0, actual_cost: 0, downtime_hours: 0, status: 'open', resolution_notes: '' });
const warranty = reactive({ fixed_asset_id: '', warranty_provider: '', warranty_type: 'standard', warranty_number: '', start_date: today, end_date: today, coverage_details: '', contact_person: '', contact_number: '', email: '', status: 'active' });
const policy = reactive({ policy_number: '', insurer_name: '', policy_type: 'comprehensive', start_date: today, end_date: today, insured_value: 0, premium_amount: 0, deductible_amount: 0, status: 'active' });
const meter = reactive({ fixed_asset_id: '', meter_type: 'running_hours', reading_date: today, reading_value: 0, unit: 'hours', remarks: '' });
const revaluation = reactive({ fixed_asset_id: '', revaluation_date: today, revalued_amount: 0, valuation_reference: '', valuer_name: '', remarks: '', status: 'draft' });
const impairment = reactive({ fixed_asset_id: '', impairment_date: today, recoverable_amount: 0, impairment_reason: '', valuation_reference: '', status: 'draft' });
const disposal = reactive({ fixed_asset_id: '', disposal_date: today, disposal_type: 'sale', buyer_customer_id: '', buyer_name: '', sale_value: 0, tax_amount: 0, disposal_expense: 0, reason: '', status: 'draft' });
const verification = reactive({ branch_id: '', verification_date: today, location_id: '', assigned_to: '', status: 'draft', remarks: '', items: [{ fixed_asset_id: '', expected_location_id: '', found_location_id: '', expected_employee_id: '', found_employee_id: '', verification_status: 'found', condition_status: 'good', notes: '' }] });

const tabs = ['dashboard', 'register', 'masters', 'acquisition', 'depreciation', 'assignment', 'transfer', 'maintenance', 'warranty', 'valuation', 'verification', 'labels', 'reports'];
const money = (v) => Number(v || 0).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const capture = (e) => { errors.value = e?.response?.data?.errors || { form: [e?.response?.data?.message || 'Unable to save.'] }; };
const firstError = computed(() => errors.value.form?.[0] || Object.values(errors.value)[0]?.[0] || '');
const clearErrors = () => { errors.value = {}; };
const add = (rows, row) => rows.push({ ...row });
const selectedAsset = (id) => refs.value.assets.find((a) => Number(a.id) === Number(id));
const applyCategoryDefaults = () => { const c = refs.value.categories.find((x) => Number(x.id) === Number(asset.asset_category_id)); if (c) { asset.depreciation_method = c.default_depreciation_method; asset.useful_life_months = c.default_useful_life_months || asset.useful_life_months; asset.depreciation_rate = c.default_depreciation_rate || ''; } };
const exportCsv = (rows, filename) => { const safe = rows || []; const headers = Object.keys(safe[0] || { empty: '' }).filter((h) => typeof safe[0]?.[h] !== 'object'); const csv = [headers.join(','), ...safe.map((r) => headers.map((h) => `"${String(r[h] ?? '').replaceAll('"', '""')}"`).join(','))].join('\n'); const link = document.createElement('a'); link.href = URL.createObjectURL(new Blob([csv], { type: 'text/csv' })); link.download = filename; link.click(); };
const printLabel = (row) => { const win = window.open('', '_blank'); win.document.write(`<body style="font-family:Arial;padding:18px"><div style="border:1px solid #111;width:260px;padding:12px"><b>${row.asset_tag}</b><p>${row.asset_number}</p><p>${row.asset_name}</p><p>${row.serial_number || ''}</p></div></body>`); win.document.close(); win.print(); };

const load = async () => {
    loading.value = true;
    try {
        refs.value = await FixedAssetApi.references();
        dashboard.value = await FixedAssetApi.dashboard(filters);
        categories.value = (await FixedAssetApi.categories()).categories || [];
        locations.value = (await FixedAssetApi.locations()).locations || [];
        assets.value = (await FixedAssetApi.assets(filters)).assets || [];
        acquisitions.value = (await FixedAssetApi.acquisitions()).acquisitions || [];
        runs.value = (await FixedAssetApi.depreciationRuns()).runs || [];
        reports.value = await FixedAssetApi.reports();
    } finally { loading.value = false; }
};
const run = async (fn) => { saving.value = true; clearErrors(); try { await fn(); await load(); } catch (e) { capture(e); } finally { saving.value = false; } };
const saveCategory = () => run(() => FixedAssetApi.saveCategory({ ...category }));
const saveLocation = () => run(() => FixedAssetApi.saveLocation({ ...location }));
const saveAsset = () => run(() => FixedAssetApi.saveAsset({ ...asset }));
const saveAcquisition = (status) => run(() => FixedAssetApi.saveAcquisition({ ...acquisition, status }));
const postAcquisition = (row) => run(() => FixedAssetApi.postAcquisition(row.id));
const capitalize = () => run(() => FixedAssetApi.capitalize({ ...cap }));
const saveDepRun = (status) => run(() => FixedAssetApi.saveDepreciationRun({ ...dep, status }));
const postDep = (row) => run(() => FixedAssetApi.postDepreciation(row.id));
const saveAssign = () => run(() => FixedAssetApi.assign({ ...assign }));
const saveTransfer = (status) => run(() => FixedAssetApi.transfer({ ...transfer, status, items: transfer.items.map((i) => ({ ...i })) }));
const saveMaintenance = (status) => run(() => FixedAssetApi.maintenance({ ...maintenance, status }));
const saveWarranty = () => run(() => FixedAssetApi.simple('warranty', { ...warranty }));
const savePolicy = () => run(() => FixedAssetApi.simple('insurance', { ...policy }));
const saveMeter = () => run(() => FixedAssetApi.simple('meter', { ...meter }));
const saveRevaluation = (status) => run(() => FixedAssetApi.revalue({ ...revaluation, status }));
const saveImpairment = (status) => run(() => FixedAssetApi.impair({ ...impairment, status }));
const saveDisposal = (status) => run(() => FixedAssetApi.dispose({ ...disposal, status }));
const saveVerification = (status) => run(() => FixedAssetApi.verification({ ...verification, status, items: verification.items.map((i) => ({ ...i })) }));
onMounted(load);
</script>

<template>
    <Layout page="fixed-assets" title="Fixed Assets">
        <div class="asset-page">
            <div class="page-heading"><div><span>FIXED ASSETS</span><h1>Asset Register & Depreciation</h1><p>Asset lifecycle, depreciation, maintenance, verification and accounting reconciliation.</p></div><button :disabled="loading" @click="load">Refresh</button></div>
            <div class="filters"><input v-model="filters.search" placeholder="Search asset, tag, serial" @keyup.enter="load" /><select v-model="filters.branch_id" @change="load"><option value="">Branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><select v-model="filters.asset_category_id" @change="load"><option value="">Category</option><option v-for="c in refs.categories" :key="c.id" :value="c.id">{{ c.category_name }}</option></select><select v-model="filters.asset_status" @change="load"><option value="">Status</option><option>draft</option><option>active</option><option>under_maintenance</option><option>impaired</option><option>disposed</option><option>sold</option><option>written_off</option></select></div>
            <div class="tabs"><button v-for="t in tabs" :key="t" :class="{active: tab === t}" @click="tab = t">{{ t }}</button></div>
            <div v-if="firstError" class="alert">{{ firstError }}</div>

            <section v-if="tab === 'dashboard'" class="panel cards"><div><span>Total Assets</span><strong>{{ dashboard.total_assets || 0 }}</strong></div><div><span>Gross Value</span><strong>Rs. {{ money(dashboard.gross_asset_value) }}</strong></div><div><span>Accum. Dep.</span><strong>Rs. {{ money(dashboard.accumulated_depreciation) }}</strong></div><div><span>Net Value</span><strong>Rs. {{ money(dashboard.net_asset_value) }}</strong></div><div><span>Current Dep.</span><strong>Rs. {{ money(dashboard.current_period_depreciation) }}</strong></div><div><span>Added</span><strong>{{ dashboard.assets_added || 0 }}</strong></div><div><span>Disposed</span><strong>{{ dashboard.assets_disposed || 0 }}</strong></div><div><span>Fully Dep.</span><strong>{{ dashboard.fully_depreciated_assets || 0 }}</strong></div><div><span>Maintenance</span><strong>{{ dashboard.assets_under_maintenance || 0 }}</strong></div><div><span>Warranty Exp.</span><strong>{{ dashboard.warranty_expiring || 0 }}</strong></div><div><span>Insurance Exp.</span><strong>{{ dashboard.insurance_expiring || 0 }}</strong></div><div><span>Missing</span><strong>{{ dashboard.missing_assets || 0 }}</strong></div></section>

            <section v-if="tab === 'register'" class="panel">
                <div class="form-grid"><select v-model="asset.branch_id"><option value="">Branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><select v-model="asset.asset_category_id" @change="applyCategoryDefaults"><option value="">Category</option><option v-for="c in refs.categories" :key="c.id" :value="c.id">{{ c.category_name }}</option></select><input v-model="asset.asset_tag" placeholder="Asset tag" /><input v-model="asset.asset_name" placeholder="Asset name" /><input v-model="asset.serial_number" placeholder="Serial" /><select v-model="asset.supplier_id"><option value="">Supplier</option><option v-for="s in refs.suppliers" :key="s.id" :value="s.id">{{ s.name }}</option></select><input v-model="asset.acquisition_date" type="date" /><input v-model.number="asset.purchase_cost" type="number" step="0.01" placeholder="Purchase cost" /><input v-model.number="asset.additional_cost" type="number" step="0.01" placeholder="Additional cost" /><input v-model.number="asset.residual_value" type="number" step="0.01" placeholder="Residual" /><select v-model="asset.depreciation_method"><option>straight_line</option><option>written_down_value</option><option>units_of_production</option><option>no_depreciation</option></select><input v-model.number="asset.useful_life_months" type="number" placeholder="Life months" /><select v-model="asset.current_location_id"><option value="">Location</option><option v-for="l in refs.locations" :key="l.id" :value="l.id">{{ l.location_name }}</option></select><select v-model="asset.condition_status"><option>new</option><option>good</option><option>fair</option><option>poor</option><option>damaged</option><option>under_repair</option><option>obsolete</option><option>scrapped</option></select><select v-model="asset.asset_status"><option>draft</option><option>pending_approval</option><option>active</option><option>inactive</option></select><textarea v-model="asset.remarks" placeholder="Remarks"></textarea></div>
                <div class="actions"><button :disabled="saving" @click="saveAsset">Save Asset</button></div>
                <div class="table-wrapper"><table><thead><tr><th>No.</th><th>Tag</th><th>Name</th><th>Category</th><th>Branch</th><th>Cost</th><th>Dep.</th><th>NBV</th><th>Condition</th><th>Status</th><th></th></tr></thead><tbody><tr v-for="a in assets" :key="a.id"><td>{{ a.asset_number }}</td><td>{{ a.asset_tag }}</td><td>{{ a.asset_name }}</td><td>{{ a.category?.category_name }}</td><td>{{ a.branch?.name }}</td><td>Rs. {{ money(a.capitalized_cost) }}</td><td>Rs. {{ money(a.accumulated_depreciation) }}</td><td>Rs. {{ money(a.net_book_value) }}</td><td>{{ a.condition_status }}</td><td>{{ a.asset_status }}</td><td><button @click="printLabel(a)">Label</button></td></tr></tbody></table></div>
            </section>

            <section v-if="tab === 'masters'" class="panel split"><div><h3>Asset Category</h3><div class="form-grid two"><input v-model="category.category_code" placeholder="Code" /><input v-model="category.category_name" placeholder="Name" /><select v-model="category.asset_account_id"><option value="">Asset account</option><option v-for="a in refs.accounts" :key="a.id" :value="a.id">{{ a.account_name }}</option></select><select v-model="category.accumulated_depreciation_account_id"><option value="">Accumulated dep account</option><option v-for="a in refs.accounts" :key="a.id" :value="a.id">{{ a.account_name }}</option></select><select v-model="category.depreciation_expense_account_id"><option value="">Dep expense account</option><option v-for="a in refs.accounts" :key="a.id" :value="a.id">{{ a.account_name }}</option></select><input v-model.number="category.default_useful_life_months" type="number" placeholder="Life months" /><button :disabled="saving" @click="saveCategory">Save Category</button></div></div><div><h3>Asset Location</h3><div class="form-grid two"><select v-model="location.branch_id"><option value="">Branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><input v-model="location.location_code" placeholder="Code" /><input v-model="location.location_name" placeholder="Name" /><select v-model="location.location_type"><option>branch</option><option>warehouse</option><option>office</option><option>floor</option><option>room</option><option>rack</option><option>employee_location</option><option>external_location</option></select><input v-model="location.floor" placeholder="Floor" /><input v-model="location.room" placeholder="Room" /><button :disabled="saving" @click="saveLocation">Save Location</button></div></div></section>

            <section v-if="tab === 'acquisition'" class="panel"><div class="form-grid"><select v-model="acquisition.branch_id"><option value="">Branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><input v-model="acquisition.acquisition_date" type="date" /><select v-model="acquisition.source_type"><option>manual</option><option>purchase_invoice</option><option>expense</option><option>opening</option><option>construction_in_progress</option><option>transfer</option><option>donation</option><option>lease</option></select><select v-model="acquisition.asset_category_id"><option value="">Category</option><option v-for="c in refs.categories" :key="c.id" :value="c.id">{{ c.category_name }}</option></select><select v-model="acquisition.supplier_id"><option value="">Supplier</option><option v-for="s in refs.suppliers" :key="s.id" :value="s.id">{{ s.name }}</option></select><input v-model.number="acquisition.quantity" type="number" /><input v-model.number="acquisition.base_cost" type="number" step="0.01" placeholder="Base cost" /><input v-model.number="acquisition.additional_cost" type="number" step="0.01" placeholder="Additional" /><input v-model.number="acquisition.tax_amount" type="number" step="0.01" placeholder="GST" /><input v-model.number="acquisition.non_creditable_tax_amount" type="number" step="0.01" placeholder="Non-credit tax" /><textarea v-model="acquisition.narration" placeholder="Narration"></textarea></div><div class="actions"><button :disabled="saving" @click="saveAcquisition('draft')">Save Draft</button><button :disabled="saving" @click="saveAcquisition('posted')">Post</button></div><div class="table-wrapper"><table><tbody><tr v-for="a in acquisitions" :key="a.id"><td>{{ a.acquisition_number }}</td><td>{{ a.acquisition_date }}</td><td>{{ a.category?.category_name }}</td><td>{{ a.quantity }}</td><td>Rs. {{ money(a.total_capitalizable_cost) }}</td><td>{{ a.status }}</td><td><button @click="postAcquisition(a)">Post</button></td></tr></tbody></table></div><h3>Capitalization</h3><div class="form-grid"><select v-model="cap.branch_id"><option value="">Branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><input v-model="cap.capitalization_date" type="date" /><select v-model="cap.fixed_asset_id"><option value="">Create new asset</option><option v-for="a in refs.assets" :key="a.id" :value="a.id">{{ a.asset_number }} - {{ a.asset_name }}</option></select><select v-model="cap.asset_category_id"><option value="">Category</option><option v-for="c in refs.categories" :key="c.id" :value="c.id">{{ c.category_name }}</option></select><input v-model.number="cap.capitalized_amount" type="number" step="0.01" /><select v-model="cap.asset_location_id"><option value="">Location</option><option v-for="l in refs.locations" :key="l.id" :value="l.id">{{ l.location_name }}</option></select><input v-model="cap.asset_name" placeholder="New asset name" /><button :disabled="saving" @click="capitalize">Capitalize</button></div></section>

            <section v-if="tab === 'depreciation'" class="panel"><div class="form-grid"><select v-model="dep.branch_id"><option value="">All branches</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><input v-model="dep.financial_year" placeholder="FY" /><input v-model="dep.period_start" type="date" /><input v-model="dep.period_end" type="date" /><input v-model="dep.posting_date" type="date" /><select v-model="dep.status"><option>calculated</option><option>posted</option></select><button :disabled="saving" @click="saveDepRun(dep.status)">Run Depreciation</button></div><div class="table-wrapper"><table><thead><tr><th>No.</th><th>Period</th><th>Assets</th><th>Processed</th><th>Skipped</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody><tr v-for="r in runs" :key="r.id"><td>{{ r.run_number }}</td><td>{{ r.period_start }} to {{ r.period_end }}</td><td>{{ r.total_assets }}</td><td>{{ r.processed_assets }}</td><td>{{ r.skipped_assets }}</td><td>Rs. {{ money(r.total_depreciation) }}</td><td>{{ r.status }}</td><td><button @click="postDep(r)">Post</button></td></tr></tbody></table></div></section>

            <section v-if="tab === 'assignment'" class="panel"><div class="form-grid"><select v-model="assign.fixed_asset_id"><option value="">Asset</option><option v-for="a in refs.assets" :key="a.id" :value="a.id">{{ a.asset_number }} - {{ a.asset_name }}</option></select><input v-model="assign.assigned_to_employee_id" placeholder="Employee ID" /><select v-model="assign.assigned_location_id"><option value="">Location</option><option v-for="l in refs.locations" :key="l.id" :value="l.id">{{ l.location_name }}</option></select><input v-model="assign.assignment_date" type="date" /><input v-model="assign.expected_return_date" type="date" /><select v-model="assign.condition_at_issue"><option>new</option><option>good</option><option>fair</option><option>poor</option><option>damaged</option></select><textarea v-model="assign.issue_notes" placeholder="Issue notes"></textarea><button :disabled="saving" @click="saveAssign">Assign Asset</button></div></section>

            <section v-if="tab === 'transfer'" class="panel"><div class="form-grid"><input v-model="transfer.transfer_date" type="date" /><select v-model="transfer.source_branch_id"><option value="">Source branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><select v-model="transfer.destination_branch_id"><option value="">Destination branch</option><option v-for="b in refs.branches" :key="b.id" :value="b.id">{{ b.name }}</option></select><select v-model="transfer.source_location_id"><option value="">Source location</option><option v-for="l in refs.locations" :key="l.id" :value="l.id">{{ l.location_name }}</option></select><select v-model="transfer.destination_location_id"><option value="">Destination location</option><option v-for="l in refs.locations" :key="l.id" :value="l.id">{{ l.location_name }}</option></select><select v-model="transfer.transfer_type"><option>branch_transfer</option><option>location_transfer</option><option>employee_transfer</option><option>department_transfer</option><option>external_temporary_transfer</option></select><textarea v-model="transfer.remarks" placeholder="Remarks"></textarea></div><div v-for="(i, n) in transfer.items" :key="n" class="line-grid"><select v-model="i.fixed_asset_id"><option value="">Asset</option><option v-for="a in refs.assets" :key="a.id" :value="a.id">{{ a.asset_number }} - {{ a.asset_name }}</option></select><input v-model="i.destination_employee_id" placeholder="Destination employee" /><select v-model="i.condition_before"><option>new</option><option>good</option><option>fair</option><option>poor</option><option>damaged</option></select><button @click="transfer.items.splice(n,1)" :disabled="transfer.items.length === 1">Remove</button></div><div class="actions"><button @click="add(transfer.items, { fixed_asset_id: '', source_employee_id: '', destination_employee_id: '', condition_before: 'good', condition_after: '' })">Add Asset</button><button :disabled="saving" @click="saveTransfer('draft')">Save</button><button :disabled="saving" @click="saveTransfer('received')">Receive</button></div></section>

            <section v-if="tab === 'maintenance'" class="panel"><div class="form-grid"><select v-model="maintenance.fixed_asset_id"><option value="">Asset</option><option v-for="a in refs.assets" :key="a.id" :value="a.id">{{ a.asset_name }}</option></select><input v-model="maintenance.request_date" type="date" /><select v-model="maintenance.maintenance_type"><option>preventive</option><option>corrective</option><option>breakdown</option><option>inspection</option><option>calibration</option><option>warranty</option><option>upgrade</option></select><select v-model="maintenance.priority"><option>low</option><option>medium</option><option>high</option><option>urgent</option></select><select v-model="maintenance.assigned_vendor_id"><option value="">Vendor</option><option v-for="s in refs.suppliers" :key="s.id" :value="s.id">{{ s.name }}</option></select><input v-model.number="maintenance.estimated_cost" type="number" step="0.01" /><input v-model.number="maintenance.actual_cost" type="number" step="0.01" /><select v-model="maintenance.status"><option>open</option><option>approved</option><option>scheduled</option><option>in_progress</option><option>completed</option><option>rejected</option><option>cancelled</option></select><textarea v-model="maintenance.issue_description" placeholder="Issue description"></textarea><textarea v-model="maintenance.resolution_notes" placeholder="Resolution"></textarea><button :disabled="saving" @click="saveMaintenance(maintenance.status)">Save Maintenance</button></div></section>

